import { useCallback, useEffect, useSyncExternalStore } from "react";
import { DEFAULT_THEME, getTheme, listThemes, type Theme } from "@t3tools/shared/themes";

export type { Theme };

const STORAGE_KEY = "t3code:custom-theme";

let listeners: Array<() => void> = [];
let lastSnapshot: Theme | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

function getStored(): Theme {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (raw) return getTheme(raw);
  return DEFAULT_THEME;
}

function applyCustomTheme(theme: Theme, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  const el = document.documentElement;
  const { colors } = theme;

  el.style.setProperty("--background", colors.background);
  el.style.setProperty("--foreground", colors.foreground);
  el.style.setProperty("--card", colors.sidebar);
  el.style.setProperty("--card-foreground", colors.foreground);
  el.style.setProperty("--popover", colors.sidebar);
  el.style.setProperty("--popover-foreground", colors.foreground);
  el.style.setProperty("--primary", colors.accent);
  el.style.setProperty("--ring", colors.accent);
  el.style.setProperty("--t3-editor-bg", colors.editor);
  el.style.setProperty("--t3-terminal-bg", colors.terminal);
  el.style.setProperty("--t3-status-bar-bg", colors.statusBar);

  document.body.style.fontFamily = theme.fontFamily;
  document.body.style.fontSize = `${theme.fontSize}px`;

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyCustomTheme(getStored());

function getSnapshot(): Theme {
  const theme = getStored();
  if (lastSnapshot && lastSnapshot.id === theme.id) {
    return lastSnapshot;
  }
  lastSnapshot = theme;
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyCustomTheme(getStored(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useCustomTheme() {
  const theme = useSyncExternalStore(subscribe, getSnapshot);

  const setTheme = useCallback((id: string) => {
    const next = getTheme(id);
    localStorage.setItem(STORAGE_KEY, next.id);
    applyCustomTheme(next, true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyCustomTheme(theme);
  }, [theme]);

  return {
    theme,
    setTheme,
    availableThemes: listThemes(),
  } as const;
}

